+            format!("{millions:.0}M")
+        } else {
+            format!("{millions:.1}M")
+        }
+    } else if count >= 1_000 {
+        let thousands = f64::from(count) / 1_000.0;
+        if thousands.fract() == 0.0 {
+            format!("{thousands:.0}K")
+        } else {
