+#[async_trait]
+impl Provider for GeminiProvider {
+    fn name(&self) -> &'static str {
+        "google"
+    }
+
+    fn api(&self) -> &'static str {
+        "gemini"
+    }
+
+    async fn stream(
+        &self,
+        context: &Context,
+        options: &StreamOptions,
+    ) -> Result<Pin<Box<dyn Stream<Item = Result<StreamEvent>> + Send>>> {
+        let api_key = options
+            .api_key
+            .clone()
+            .or_else(|| std::env::var("GOOGLE_API_KEY").ok())
+            .or_else(|| std::env::var("GEMINI_API_KEY").ok())
+            .ok_or_else(|| Error::config("Missing Google/Gemini API key"))?;
+
+        let request_body = self.build_request(context, options);
+        let url = self.streaming_url(&api_key);
+
+        // Build request
+        let mut request = self
+            .client
+            .post(&url)
+            .header("Content-Type", "application/json");
+
+        for (key, value) in &options.headers {
+            request = request.header(key, value);
+        }
+
+        let request = request.json(&request_body);
+
+        // Create event source for SSE streaming
+        let event_source = EventSource::new(request).map_err(|e| Error::api(e.to_string()))?;
+
+        // Create stream state
+        let model = self.model.clone();
+        let api = self.api().to_string();
+        let provider = self.name().to_string();
+
+        let stream = stream::unfold(
+            StreamState::new(event_source, model, api, provider),
+            |mut state| async move {
+                loop {
+                    match state.event_source.next().await {
+                        Some(Ok(Event::Open)) => {}
+                        Some(Ok(Event::Message(msg))) => {
+                            match state.process_event(&msg.data) {
+                                Ok(Some(event)) => return Some((Ok(event), state)),
+                                Ok(None) => {}
+                                Err(e) => return Some((Err(e), state)),
+                            }
+                        }
+                        Some(Err(e)) => {
+                            // Check if it's just the stream ending
+                            let err_str = e.to_string();
+                            if err_str.contains("end of stream")
+                                || err_str.contains("connection closed")
+                            {
+                                // Stream ended, emit final Done event
+                                if !state.finished {
+                                    state.finished = true;
+                                    state.finalize_content();
+                                    return Some((
+                                        Ok(StreamEvent::Done {
+                                            reason: state.partial.stop_reason,
+                                            message: state.partial.clone(),
+                                        }),
+                                        state,
+                                    ));
+                                }
+                                return None;
+                            }
+                            let err = Error::api(format!("SSE error: {e}"));
+                            return Some((Err(err), state));
+                        }
+                        None => {
+                            // Stream ended naturally
+                            if !state.finished {
+                                state.finished = true;
+                                state.finalize_content();
+                                return Some((
+                                    Ok(StreamEvent::Done {
+                                        reason: state.partial.stop_reason,
+                                        message: state.partial.clone(),
+                                    }),
+                                    state,
+                                ));
+                            }
+                            return None;
+                        }
+                    }
+                }
+            },
+        );
+
+        Ok(Box::pin(stream))
+    }
+}
