+fn convert_tool_to_gemini(tool: &ToolDef) -> GeminiFunctionDeclaration {
+    GeminiFunctionDeclaration {
+        name: tool.name.clone(),
+        description: tool.description.clone(),
+        parameters: tool.parameters.clone(),
+    }
+}
